UPDATE inventory
SET available_stock = available_stock - #{quantity},
    frozen_stock = frozen_stock + #{quantity},
    version = version + 1
WHERE sku_id = #{skuId}
  AND available_stock >= #{quantity}

UPDATE inventory
SET frozen_stock = frozen_stock - #{quantity},
    version = version + 1
WHERE sku_id = #{skuId}
  AND frozen_stock >= #{quantity}

UPDATE inventory
SET available_stock = available_stock + #{quantity},
    frozen_stock = frozen_stock - #{quantity},
    version = version + 1
WHERE sku_id = #{skuId}
  AND frozen_stock >= #{quantity}
